export function run({
  exists = existsSync,
  readFile = readFileSync,
  projectDir = process.env.CLAUDE_PROJECT_DIR ?? process.cwd(),
} = {}) {
  // Priorité : .claude/agent-rules.md > CONVENTIONS.md > absent (no-op)
  const candidates = [
    join(projectDir, '.claude', 'agent-rules.md'),
    join(projectDir, 'CONVENTIONS.md'),
