#!/usr/bin/env node
// Vérifie que les dépendances du projet sont à jour au démarrage de session (SessionStart)
import { existsSync, statSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';

const SPECS = [
  ['pnpm-lock.yaml', 'node_modules', 'pnpm install'],
  ['package-lock.json', 'node_modules', 'npm ci'],
  ['yarn.lock', 'node_modules', 'yarn install --frozen-lockfile'],
  ['requirements.txt', '.venv', 'pip install -r requirements.txt'],
];

export function run({
  exists = existsSync,
  stat = statSync,
  projectDir = process.env.CLAUDE_PROJECT_DIR ?? process.cwd(),
} = {}) {
  const warnings = [];

  for (const [lockfile, modulesDir, installCmd] of SPECS) {
    const lock = join(projectDir, lockfile);
    const mods = join(projectDir, modulesDir);
    if (!exists(lock)) continue;
    if (!exists(mods)) {
      warnings.push(`[setup-check-deps] ⚠ ${modulesDir} absent — lancez : ${installCmd}\n`);
      continue;
    }
    if (stat(lock).mtimeMs > stat(mods).mtimeMs) {
      warnings.push(`[setup-check-deps] ⚠ ${lockfile} plus récent que ${modulesDir} — lancez : ${installCmd}\n`);
    }
  }

  return { warnings, message: warnings.join('') };
}

/* v8 ignore next 4 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result.message) process.stderr.write(result.message);
}

#!/usr/bin/env node
// Nettoie les fichiers temporaires Claude datant de plus de 24h (SessionEnd)
import { readdirSync, statSync, unlinkSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';

const MAX_AGE_MS = 24 * 60 * 60 * 1_000;
const PREFIX = 'claude-';

export function run({
  readdir = readdirSync,
  stat = statSync,
  unlink = unlinkSync,
  tmp = '/tmp',
  maxAge = MAX_AGE_MS,
  now = () => Date.now(),
} = {}) {
  let cleaned = 0;
  try {
    for (const f of readdir(tmp)) {
      if (!f.startsWith(PREFIX)) continue;
      const fp = join(tmp, f);
      try {
        const age = now() - stat(fp).mtimeMs;
        if (age > maxAge) {
          unlink(fp);
          cleaned++;
        }
      } catch {}
    }
  } catch {}

  return cleaned > 0
    ? { cleaned, message: `[session-end-cleanup] ${cleaned} fichier(s) temporaire(s) supprimé(s).\n` }
    : { cleaned: 0 };
}

/* v8 ignore next 4 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result?.message) process.stderr.write(result.message);
}

#!/usr/bin/env node
// Réinjecte le contexte sauvegardé avant la dernière compaction (SessionStart)
import { readFileSync, existsSync, readdirSync } from 'fs';
import { join } from 'path';
import { fileURLToPath } from 'url';

export function run(
  input,
  {
    exists = existsSync,
    readFile = readFileSync,
    readdir = readdirSync,
    backupDir = '/tmp/claude-compact-backups',
  } = {},
) {
  const sessionId = input.session_id ?? '';
  if (!exists(backupDir)) return null;

  // Cherche le backup de la session courante en priorité, sinon le plus récent
  let backupFile = sessionId ? join(backupDir, `${sessionId}.json`) : null;

  if (!backupFile || !exists(backupFile)) {
    const files = readdir(backupDir)
      .filter((f) => f.endsWith('.json'))
      .map((f) => ({
        f,
        mtime: new Date(readFile(join(backupDir, f), 'utf8').split('"saved_at":"')[1]?.split('"')[0] ?? 0),
      }))
      .sort((a, b) => b.mtime - a.mtime);
    backupFile = files[0] ? join(backupDir, files[0].f) : null;
  }

  if (!backupFile || !exists(backupFile)) return null;

  try {
    const { summary, saved_at } = JSON.parse(readFile(backupFile, 'utf8'));
    if (summary) {
      return `## Contexte de la session précédente (avant compaction du ${saved_at})\n\n${summary}\n`;
    }
  } catch {
    // Fichier corrompu — ignorer silencieusement
  }
  return null;
}

/* v8 ignore next 5 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const input = JSON.parse(readFileSync(0, 'utf8'));
  const result = run(input);
  if (result) process.stdout.write(result);
}

