#!/usr/bin/env node
// SessionStart: crée un worktree isolé si la session démarre sur main/master.
// Nettoie automatiquement les worktrees dont la branche a été mergée dans main.
import { execSync } from 'child_process';
import { existsSync } from 'fs';
import { fileURLToPath } from 'url';

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

function defaultAddWorktree(path, branchName) {
  execSync(`git worktree add "${path}" -b "${branchName}"`, {
    encoding: 'utf8',
    timeout: 15_000,
    stdio: ['ignore', 'ignore', 'ignore'],
  });
}

function defaultRemoveWorktree(mainRoot, wtPath, branchName) {
  try { execSync(`git -C "${mainRoot}" worktree remove --force "${wtPath}"`, { timeout: 10_000 }); } catch { /* ignore */ }
  try { execSync(`git -C "${mainRoot}" branch -D "${branchName}"`, { timeout: 5_000 }); } catch { /* ignore */ }
}

export function run({
  exec = defaultExec,
  addWorktree = defaultAddWorktree,
  removeWorktree = defaultRemoveWorktree,
  exists = existsSync,
  now = () => new Date(),
} = {}) {
  const branch = exec('git branch --show-current') || exec('git rev-parse --abbrev-ref HEAD');
  if (!branch || !/^(main|master)$/.test(branch)) return null;

  const currentRoot = exec('git rev-parse --show-toplevel');
  if (!currentRoot) return null;

  // Ne pas agir si on est déjà dans un worktree secondaire
  const worktreeList = exec('git worktree list');
  const mainRoot = worktreeList.split('\n')[0]?.split(/\s+/)[0] ?? '';
  if (mainRoot !== currentRoot) return null;

  // Récupérer les derniers commits pour détecter les merges récents
  exec('git fetch --quiet origin main');

  // Nettoyer les worktrees dont la branche est fusionnée dans origin/main
  const mergedBranches = new Set(
    exec('git branch --merged origin/main')
      .split('\n')
      .map((b) => b.trim().replace(/^\*\s*/, ''))
      .filter(Boolean),
  );

  const secondaryLines = exec('git worktree list').split('\n').slice(1);
  for (const line of secondaryLines) {
    if (!line.trim()) continue;
    const parts = line.split(/\s+/);
    const wtPath = parts[0];
    const wtBranch = (parts[2] ?? '').replace(/^\[|\]$/g, '');
    if (wtBranch && mergedBranches.has(wtBranch)) {
      removeWorktree(mainRoot, wtPath, wtBranch);
    }
  }

  const date = now().toISOString().slice(0, 10).replace(/-/g, '');
  const projectName = currentRoot.split('/').pop() ?? 'project';
  const branchName = `work/session-${date}`;
  const worktreePath = `${currentRoot}/../${projectName}-work-${date}`;

  // Vérifier si un worktree pour aujourd'hui existe encore (non mergé)
  const freshList = exec('git worktree list');
  const todayLine = freshList.split('\n').slice(1).find((l) => l.includes(branchName));
  if (todayLine) {
    const wtPath = todayLine.split(/\s+/)[0];
    return [
      `## Worktree session existant`,
      `- Session démarrée sur \`main\`. Le worktree du jour est déjà actif.`,
      `- **Chemin** : \`${wtPath}\``,
      `- **Branche** : \`${branchName}\``,
      `- Effectuez vos modifications dans ce worktree, pas dans le dépôt principal.`,
    ].join('\n') + '\n';
  }

  // Créer un worktree frais depuis main
  try {
    addWorktree(worktreePath, branchName);
  } catch {
    return [
      `## ⚠️  Session démarrée sur \`main\``,
      `- Impossible de créer un worktree automatiquement (branche \`${branchName}\` peut-être déjà existante).`,
      `- Créez manuellement un worktree ou une branche avant de modifier des fichiers.`,
    ].join('\n') + '\n';
  }

  if (!exists(worktreePath)) return null;

  return [
    `## Worktree isolé créé automatiquement`,
    `- Session démarrée sur \`main\` : un worktree a été créé pour isoler les modifications.`,
    `- **Chemin** : \`${worktreePath}\``,
    `- **Branche** : \`${branchName}\``,
    `- Travaillez dans ce worktree — évitez de modifier des fichiers dans le dépôt principal.`,
  ].join('\n') + '\n';
}

/* v8 ignore next 4 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result) process.stdout.write(result);
}

#!/usr/bin/env node
// SessionStart: si on est sur main/master et qu'il y a des commits distants, lance git pull
import { execSync } from 'child_process';
import { fileURLToPath } from 'url';

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 10_000 }).trim(); } catch { return ''; }
}

function defaultPull() {
  execSync('git pull --ff-only --quiet', { encoding: 'utf8', timeout: 30_000 });
}

export function run({ exec = defaultExec, pull = defaultPull } = {}) {
  const branch = exec('git branch --show-current') || exec('git rev-parse --abbrev-ref HEAD');
  if (!branch || !/^(main|master)$/.test(branch)) return null;

  // Vérifier qu'un remote existe
  const remote = exec('git remote');
  if (!remote) return null;

  // Fetch silencieux pour connaître l'état du remote
  exec('git fetch --quiet 2>/dev/null');

  const localHash = exec('git rev-parse HEAD');
  const remoteHash = exec('git rev-parse @{u} 2>/dev/null');
  if (!remoteHash || localHash === remoteHash) return null;

  // Vérifier qu'on n'est pas en avance sur le remote (merge sûr)
  const behind = exec('git rev-list HEAD..@{u} --count');
  const ahead = exec('git rev-list @{u}..HEAD --count');
  if (parseInt(behind, 10) === 0) return null;

  if (parseInt(ahead, 10) > 0) {
    // Divergence — ne pas pull automatiquement
    return [
      `## ⚠️  Branche \`${branch}\` diverge du remote`,
      `- ${behind} commit(s) en retard, ${ahead} commit(s) en avance.`,
      `- Résolvez la divergence avant de continuer (\`git pull --rebase\` ou merge manuel).`,
    ].join('\n') + '\n';
  }

  // Pull sans divergence
  try {
    pull();
  } catch {
    return `## ⚠️  \`git pull\` a échoué sur \`${branch}\` — synchronisez manuellement.\n`;
  }

  return [
    `## Dépôt synchronisé`,
    `- \`${behind}\` commit(s) récupéré(s) depuis le remote sur \`${branch}\`.`,
  ].join('\n') + '\n';
}

/* v8 ignore next 4 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result) process.stdout.write(result);
}

#!/usr/bin/env node
// SessionStart: avertit si des stashs Git non récupérés traînent depuis plusieurs jours
import { execSync } from 'child_process';
import { fileURLToPath } from 'url';

const DAYS = 3;

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 5_000 }).trim(); } catch { return ''; }
}

export function run({ exec = defaultExec, now = () => Date.now() } = {}) {
  const stashList = exec('git stash list --format="%gd|%ci|%gs"');
  if (!stashList) return null;

  const currentTime = now();
  const threshold = DAYS * 24 * 60 * 60 * 1000;

  const stale = stashList
    .split('\n')
    .map((line) => {
      const [ref, date, ...msgParts] = line.split('|');
      const age = currentTime - new Date(date).getTime();
      return { ref, date: date?.trim(), msg: msgParts.join('|').trim(), age };
    })
    .filter((s) => s.age > threshold);

  if (stale.length === 0) return null;

  const lines = [
    `## ⚠️  Stashs Git oubliés (${stale.length})`,
    `- ${stale.length} stash(s) de plus de ${DAYS} jours détecté(s) :`,
  ];

  for (const s of stale.slice(0, 5)) {
    const days = Math.floor(s.age / (24 * 60 * 60 * 1000));
    lines.push(`  - \`${s.ref}\` (${days}j) — ${s.msg}`);
  }

  lines.push(`- Utilisez \`git stash list\` pour les voir, \`git stash pop\` ou \`git stash drop\` pour les gérer.`);

  return lines.join('\n') + '\n';
}

/* v8 ignore next 4 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const result = run();
  if (result) process.stdout.write(result);
}

#!/usr/bin/env node
// PreToolUse Write|Edit: bloque la première écriture sur main si aucun worktree n'est actif
import { readFileSync } from 'fs';
import { execSync } from 'child_process';
import { fileURLToPath } from 'url';

function defaultExec(cmd) {
  try { return execSync(cmd, { encoding: 'utf8', timeout: 5_000 }).trim(); } catch { return ''; }
}

export function run(input, { exec = defaultExec } = {}) {
  const branch = exec('git branch --show-current') || exec('git rev-parse --abbrev-ref HEAD');
  if (!branch || !/^(main|master)$/.test(branch)) return null;

  const worktreeList = exec('git worktree list');
  const currentRoot = exec('git rev-parse --show-toplevel');
  const mainRoot = worktreeList.split('\n')[0]?.split(/\s+/)[0] ?? '';
  if (mainRoot !== currentRoot) return null;

  const filePath = input.tool_input?.file_path ?? '(fichier inconnu)';

  // Autoriser les écritures vers des fichiers dans un worktree (hors du repo principal)
  if (filePath !== '(fichier inconnu)' && !filePath.startsWith(mainRoot + '/')) return null;

  return {
    decision: 'block',
    reason: `Écriture sur \`${branch}\` bloquée : vous êtes sur la branche principale.\nCréez un worktree (\`git worktree add ../mon-fix -b feat/mon-fix\`) ou changez de branche avant de modifier \`${filePath}\`.`,
  };
}

/* v8 ignore next 5 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const input = JSON.parse(readFileSync(0, 'utf8'));
  const result = run(input);
  if (result) process.stdout.write(JSON.stringify(result));
}

#!/usr/bin/env node
// Resynchronise registry.json depuis les scripts dogfoodés après édition d'un
// hook .claude/hooks/*.mjs (ou du registre lui-même). (PostToolUse Write|Edit)
import { readFileSync } from 'fs';
import { execSync } from 'child_process';
import { fileURLToPath } from 'url';

const SELF = 'registry-auto-sync.mjs';

function defaultExec(projectDir) {
  return execSync('node .claude/sync-hooks.mjs', {
    timeout: 30_000,
    cwd: projectDir,
    encoding: 'utf8',
  });
}

// Vrai si l'édition doit déclencher une resync (un hook .mjs ou le registre).
function shouldSync(filePath) {
  if (!filePath) return false;
  if (filePath.endsWith(`/${SELF}`)) return false; // évite de se resync soi-même
  if (filePath.endsWith('registry/registry.json')) return true;
  return /\.claude\/hooks\/[^/]+\.mjs$/.test(filePath);
}

export function run(input, { exec = defaultExec, projectDir = process.env.CLAUDE_PROJECT_DIR } = {}) {
  const filePath = input.tool_input?.file_path ?? '';
  if (!shouldSync(filePath) || !projectDir) return null;

  try {
    const out = exec(projectDir);
    const summary = out.trim().split('\n').slice(-3).join(' | ');
    return { message: `[registry-auto-sync] ${summary}` };
  } catch (e) {
    return { message: `[registry-auto-sync] échec sync : ${e.message}` };
  }
}

/* v8 ignore next 5 */
if (process.argv[1] === fileURLToPath(import.meta.url)) {
  const input = JSON.parse(readFileSync(0, 'utf8'));
  const result = run(input);
  if (result?.message) process.stderr.write(result.message + '\n');
}
